import json, os, glob

# Audit all user message files for credential leaks
user_files = sorted(glob.glob('.rork/history/main/*_user.json'))
results = []

for f in user_files:
    try:
        d = json.load(open(f))
        text = json.dumps(d) if isinstance(d, dict) else str(d)

        found = []
        if 'AKIA' in text: found.append('AWS_ACCESS_KEY_ID')
        if 'GNwtZwj' in text: found.append('AWS_SECRET_ACCESS_KEY')
        if 'rnd_1H0' in text: found.append('RENDER_API_KEY')
        if 'srv-d7t9' in text: found.append('RENDER_SERVICE_ID')
        if 'ghp_' in text: found.append('GITHUB_TOKEN')
        if 'X146corp' in text: found.append('OWNER_PASSWORD')
        if 'b8d6f015' in text: found.append('OWNER_TOKEN')
        if 'TaTRyViK' in text: found.append('SUPABASE_SERVICE_ROLE_KEY')
        if 'rork_sk_krty' in text: found.append('RORK_TOOLKIT_SECRET_KEY')

        if found:
            results.append((os.path.basename(f), found))
    except:
        pass

print(f'=== CREDENTIAL SHARING AUDIT ===')
print(f'Total user message files scanned: {len(user_files)}')
print(f'Files containing credentials: {len(results)}')
print()
for fname, creds in results:
    print(f'  {fname}')
    print(f'    Leaked: {\", \".join(creds)}')
    print()

# Also count all credential appearances across ALL files (assistant too)
all_files = sorted(glob.glob('.rork/history/main/*.json'))
total_aws = 0
total_render = 0
total_github = 0
total_owner = 0
total_supabase = 0
total_toolkit = 0

for f in all_files:
    try:
        text = open(f).read()
        if 'AKIASAJBIV7' in text or 'AKIATAJ2' in text: total_aws += 1
        if 'rnd_1H0' in text: total_render += 1
        if 'ghp_' in text: total_github += 1
        if 'X146corp' in text: total_owner += 1
        if 'TaTRyViK' in text: total_supabase += 1
        if 'rork_sk_krty' in text: total_toolkit += 1
    except:
        pass

print(f'=== CREDENTIAL APPEARANCES ACROSS ALL CHAT LOGS (user + assistant) ===')
print(f'  AWS credentials:     {total_aws} files')
print(f'  Render API key:      {total_render} files')
print(f'  GitHub token:        {total_github} files')
print(f'  Owner password:      {total_owner} files')
print(f'  Supabase service key: {total_supabase} files')
print(f'  Rork toolkit secret:  {total_toolkit} files')
""}

